IOT_QUESTIONS_PART2 = [{'question': 'A smart home hub is discovered to have an unencrypted REST API accessible on port 8080 that returns full device configuration including WiFi credentials when queried without authentication. Which OWASP IoT Top 10 categories does this violate?', 'options': [{'text': 'I1 Weak Passwords only — the API should require a password before returning configuration data', 'explanation': 'While authentication is required this vulnerability spans multiple OWASP categories including insecure ecosystem interfaces and insecure data transfer not just weak passwords.', 'correct': False}, {'text': 'I3 Insecure Ecosystem Interfaces and I7 Insecure Data Transfer — unauthenticated API returning sensitive data over unencrypted connection', 'explanation': 'Correct. I3 covers insecure APIs that expose device functionality without proper authentication. I7 covers transmission of sensitive data without encryption. An unauthenticated API returning WiFi credentials over HTTP violates both categories simultaneously.', 'correct': True}, {'text': 'I10 Lack of Physical Hardening only — the API is only accessible to attackers with physical network access', 'explanation': 'Physical hardening relates to physical device security not network API security. API vulnerabilities are network-accessible and do not require physical access to exploit.', 'correct': False}, {'text': 'I8 Lack of Device Management — the device cannot be properly managed without API authentication', 'explanation': 'Device management relates to lifecycle management capabilities. The primary vulnerabilities here are the unauthenticated API (I3) and unencrypted sensitive data transmission (I7).', 'correct': False}], 'overall_explanation': 'OWASP I3 and I7 frequently occur together in IoT devices. I3 (Insecure Ecosystem Interfaces) covers web interfaces, APIs, and cloud services lacking proper authentication and authorisation. I7 (Insecure Data Transfer and Storage) covers sensitive data transmitted without encryption. Both must be remediated: implement API authentication and enforce HTTPS for all API communications.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'An IoT security researcher discovers that a popular baby monitor runs BusyBox Linux with an outdated kernel containing multiple known CVEs. The vendor has not released a firmware update in 3 years. Which OWASP IoT Top 10 category best describes this?', 'options': [{'text': 'I1 Weak Passwords — the outdated kernel allows password bypass attacks', 'explanation': 'I1 covers credential weaknesses not outdated software components. Using outdated software with known vulnerabilities is specifically addressed by a different OWASP IoT category.', 'correct': False}, {'text': 'I5 Use of Insecure or Outdated Components — known vulnerable third-party components creating permanent exploitable vulnerabilities', 'explanation': 'Correct. OWASP I5 covers use of deprecated or insecure software components including outdated operating system kernels and third-party libraries with known CVEs. A 3-year-old BusyBox installation with unpatched kernel CVEs means attackers can exploit publicly documented vulnerabilities against all devices of this model.', 'correct': True}, {'text': 'I4 Lack of Secure Update Mechanism — the vendor cannot push security updates to the devices', 'explanation': 'I4 relates to the absence or insecurity of update mechanisms. While related the primary OWASP category for actually running outdated vulnerable components is I5 not I4.', 'correct': False}, {'text': 'I10 Lack of Physical Hardening — the outdated kernel allows physical access attacks', 'explanation': 'Physical hardening relates to physical attack resistance. Outdated vulnerable software components are specifically addressed by OWASP I5 regardless of physical access requirements.', 'correct': False}], 'overall_explanation': 'OWASP I5 Use of Insecure or Outdated Components is extremely common in IoT devices that use open source components without ongoing security maintenance. Mitigations: implement software bill of materials (SBOM) tracking all components and versions, establish a process for monitoring CVEs affecting used components, and commit to regular security updates throughout the device support lifecycle.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'A smart thermostat allows remote access via a cloud API. Security testing reveals the API does not implement rate limiting allowing an attacker to try thousands of password combinations per minute. Which OWASP IoT Top 10 category is this and what is the specific risk?', 'options': [{'text': 'I2 Insecure Network Services — the API service is running on an unnecessary network port', 'explanation': 'I2 covers unnecessary or insecure network services on the device itself. The cloud API rate limiting issue is an ecosystem interface vulnerability covered by a different category.', 'correct': False}, {'text': 'I3 Insecure Ecosystem Interfaces — absent rate limiting enables brute force attacks against all user accounts on the platform', 'explanation': 'Correct. OWASP I3 covers cloud interfaces and APIs that lack proper security controls including rate limiting. Without rate limiting an attacker can conduct credential stuffing or brute force attacks against all accounts on the platform potentially compromising all devices managed through that cloud service.', 'correct': True}, {'text': 'I6 Insufficient Privacy Protection — brute force access exposes personal temperature and occupancy data', 'explanation': 'Privacy data exposure is a consequence of the attack not the vulnerability itself. The root cause is the insecure ecosystem interface lacking rate limiting which is I3.', 'correct': False}, {'text': 'I9 Insecure Default Settings — the API should have rate limiting enabled by default', 'explanation': 'While default settings are a related concern the primary OWASP category for insecure cloud API controls is I3 Insecure Ecosystem Interfaces not I9.', 'correct': False}], 'overall_explanation': 'Cloud API security for IoT requires: rate limiting on authentication endpoints, account lockout after failed attempts, CAPTCHA for suspicious login patterns, multi-factor authentication options, anomaly detection for unusual access patterns, and monitoring for credential stuffing attacks. A compromised IoT cloud platform gives attackers control of all devices managed through it.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'An IoT device stores user location data, usage patterns and personal preferences in plaintext on internal flash storage. If physically accessed the storage can be read without any authentication. Which OWASP IoT Top 10 category is this?', 'options': [{'text': 'I2 Insecure Network Services — the data is accessible via network services running on the device', 'explanation': 'I2 covers network-accessible services. Plaintext storage on internal flash that requires physical access is specifically an insecure data storage issue covered by a different OWASP category.', 'correct': False}, {'text': 'I7 Insecure Data Transfer and Storage — sensitive personal data stored without encryption enabling extraction through physical access', 'explanation': 'Correct. OWASP I7 covers both insecure transmission and insecure storage of sensitive data. Plaintext storage of personal data on IoT device flash memory means physical access to the device allows complete data extraction. This is particularly concerning for devices that may be resold or discarded without data wiping.', 'correct': True}, {'text': 'I10 Lack of Physical Hardening — the device allows physical access to internal storage', 'explanation': 'I10 covers physical attack resistance such as debug port exposure and tamper protection. The specific issue here is that sensitive data is stored without encryption which is I7 regardless of physical hardening.', 'correct': False}, {'text': 'I8 Lack of Device Management — the device cannot remotely wipe stored data when decommissioned', 'explanation': 'Remote wipe capability is a device management feature. The primary vulnerability is the plaintext storage of sensitive data which is I7 Insecure Data Transfer and Storage.', 'correct': False}], 'overall_explanation': 'OWASP I7 insecure storage mitigations: encrypt all sensitive data stored on device using device-specific keys, implement secure element or TPM for key storage, provide remote wipe capability for decommissioning, minimise data stored on device preferring cloud storage with proper access controls, and ensure factory reset completely removes all personal data.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'A security audit of an IoT platform finds that when a device is sold or transferred the new owner can access all historical data from the previous owner because the cloud platform does not delete data on device re-registration. Which OWASP IoT Top 10 category is this?', 'options': [{'text': 'I4 Lack of Secure Update Mechanism — the platform cannot update device ownership securely', 'explanation': 'I4 covers firmware update security not data ownership management. Retaining previous owner data on device transfer is a privacy and data management issue.', 'correct': False}, {'text': 'I6 Insufficient Privacy Protection — personal data from previous owners retained and accessible to new device owners', 'explanation': 'Correct. OWASP I6 covers insufficient protection of personal information including failure to delete personal data when devices change ownership. Previous owner location history, usage patterns, and personal preferences being accessible to new owners is a clear privacy violation potentially breaching GDPR and other privacy regulations.', 'correct': True}, {'text': 'I8 Lack of Device Management — the platform cannot manage device ownership transitions', 'explanation': 'Device management covers operational lifecycle management. The specific privacy failure of retaining previous owner data is I6 Insufficient Privacy Protection.', 'correct': False}, {'text': 'I3 Insecure Ecosystem Interfaces — the cloud API allows unauthorised access to other users data', 'explanation': 'I3 covers API security controls. While the cloud interface is involved the root cause is insufficient privacy protection and data lifecycle management which is I6.', 'correct': False}], 'overall_explanation': 'OWASP I6 Insufficient Privacy Protection covers: collection of unnecessary personal data, failure to delete data when no longer needed, inadequate user consent for data collection, sharing data with third parties without disclosure, and failure to properly anonymise data. GDPR and other privacy regulations impose significant financial penalties for violations including inadequate data deletion on device transfer.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'An IoT device exposes a JTAG debug port that allows direct memory access and firmware extraction without authentication. Which OWASP IoT Top 10 category is this and why is it significant?', 'options': [{'text': 'I2 Insecure Network Services — the JTAG port provides network access to device internals', 'explanation': 'JTAG is a hardware debug interface not a network service. Physical hardware debug ports are covered by a specific OWASP IoT category related to physical device hardening.', 'correct': False}, {'text': 'I10 Lack of Physical Hardening — exposed debug ports allow firmware extraction enabling reverse engineering and vulnerability discovery', 'explanation': 'Correct. OWASP I10 covers physical attack resistance including exposed debug interfaces. JTAG ports allow attackers with physical access to extract firmware for offline analysis, discover hardcoded credentials, identify vulnerabilities, and potentially modify device behaviour. Production devices should have debug ports disabled or removed.', 'correct': True}, {'text': 'I5 Use of Insecure Components — JTAG is an outdated debugging technology that should be replaced', 'explanation': 'JTAG is a standard debugging interface not an insecure component. The security issue is that the debug port remains accessible in production devices which is I10 Lack of Physical Hardening.', 'correct': False}, {'text': 'I7 Insecure Data Transfer — JTAG allows data to be transferred from the device without encryption', 'explanation': 'I7 covers network data transfer and storage security. Physical debug port exposure enabling hardware-level device access is specifically I10 Lack of Physical Hardening.', 'correct': False}], 'overall_explanation': 'OWASP I10 physical hardening requirements: disable or remove debug ports (JTAG, UART) in production firmware, implement tamper detection and response, use epoxy or physical barriers to prevent PCB access, implement secure boot preventing unauthorised firmware, and conduct physical penetration testing before product release. Firmware extracted via JTAG can reveal hardcoded credentials affecting all devices of that model.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'A smart city deployment of 10000 parking sensors has no centralised device management platform. When a vulnerability is discovered there is no way to identify which sensors are affected or push a patch to them. Which OWASP IoT Top 10 category is this?', 'options': [{'text': 'I4 Lack of Secure Update Mechanism — the sensors cannot receive security updates', 'explanation': 'I4 covers the security of the update process itself. The broader issue here is the complete absence of device management capability including vulnerability identification and patch deployment which is covered by a different category.', 'correct': False}, {'text': 'I8 Lack of Device Management — absence of management infrastructure makes vulnerability response impossible at scale', 'explanation': 'Correct. OWASP I8 covers the inability to monitor, manage, update, and decommission IoT devices. Without centralised management identifying affected devices, assessing vulnerability exposure, and deploying patches across 10,000 sensors is practically impossible making the organisation permanently vulnerable to any discovered vulnerability.', 'correct': True}, {'text': 'I1 Weak Passwords — unmanaged devices cannot enforce password policies', 'explanation': 'Password policy enforcement is one aspect of device management but the primary OWASP category for the complete absence of device management infrastructure is I8 Lack of Device Management.', 'correct': False}, {'text': 'I9 Insecure Default Settings — unmanaged devices retain insecure factory default configurations', 'explanation': 'Default settings are one concern but the core vulnerability is the complete absence of management infrastructure making any security response to discovered vulnerabilities impossible which is I8.', 'correct': False}], 'overall_explanation': 'OWASP I8 Device Management is increasingly critical as IoT deployments scale to thousands or millions of devices. Essential capabilities: asset inventory tracking all deployed devices, remote firmware update delivery, remote configuration management, device health monitoring, remote decommissioning, and anomaly alerting. Without these capabilities vulnerability response at scale is impossible.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'A penetration tester discovers that an IoT device runs unnecessary services including FTP on port 21, Telnet on port 23 and an SNMP service with default community string public. Which OWASP IoT Top 10 category covers this?', 'options': [{'text': 'I9 Insecure Default Settings — the services are enabled by default in the factory configuration', 'explanation': 'While default settings contribute to the problem the specific OWASP category for unnecessary and insecure network services running on IoT devices is I2 not I9.', 'correct': False}, {'text': 'I2 Insecure Network Services — unnecessary services with known vulnerabilities and weak authentication increase attack surface unnecessarily', 'explanation': 'Correct. OWASP I2 covers network services that are unnecessary, use insecure protocols, or have weak authentication. FTP transmits credentials in plaintext, Telnet has no encryption, and SNMP with default community string public allows reading and potentially writing device configuration. Each service adds unnecessary attack surface.', 'correct': True}, {'text': 'I3 Insecure Ecosystem Interfaces — the services provide insecure interfaces to device management functions', 'explanation': 'I3 covers cloud and web ecosystem interfaces. Device-level network services like FTP, Telnet and SNMP are specifically covered by I2 Insecure Network Services.', 'correct': False}, {'text': 'I7 Insecure Data Transfer — FTP and Telnet transmit data without encryption', 'explanation': 'While unencrypted transmission is a characteristic of these services the OWASP category for running unnecessary insecure network services on IoT devices is I2. I7 specifically covers sensitive data storage and transfer practices.', 'correct': False}], 'overall_explanation': 'OWASP I2 Insecure Network Services mitigation: disable all services not required for device function, replace insecure protocols (FTP with SFTP, Telnet with SSH, SNMPv1/v2 with SNMPv3), implement firewall rules blocking access to management services from unnecessary sources, and conduct port scanning as part of device security testing before release.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'An IoT device ships with WiFi, Bluetooth, Zigbee and Z-Wave radios enabled by default even though the use case only requires WiFi connectivity. Which OWASP IoT Top 10 category does this violate?', 'options': [{'text': 'I5 Use of Insecure Components — the additional radios use outdated wireless protocols with known vulnerabilities', 'explanation': 'I5 covers vulnerable software components. Unnecessary enabled radios are a default configuration issue not specifically an outdated component issue.', 'correct': False}, {'text': 'I9 Insecure Default Settings — unnecessary radios enabled by default create additional attack surface without providing any functional benefit', 'explanation': 'Correct. OWASP I9 covers insecure default configurations including unnecessary features enabled by default. Bluetooth, Zigbee and Z-Wave radios enabled on a WiFi-only use case device create additional wireless attack surfaces without providing any user benefit. Each radio represents an additional attack vector that could be used to compromise the device.', 'correct': True}, {'text': 'I2 Insecure Network Services — the additional radios run network services that increase attack surface', 'explanation': 'I2 covers network services running on the device. The root cause here is insecure default settings enabling unnecessary hardware capabilities which is I9.', 'correct': False}, {'text': 'I10 Lack of Physical Hardening — the radios can be physically accessed by attackers', 'explanation': 'Physical hardening covers physical attack resistance. Unnecessarily enabled wireless radios are a default configuration issue covered by I9 not a physical hardening issue.', 'correct': False}], 'overall_explanation': 'OWASP I9 Insecure Default Settings principle: ship devices in the most secure configuration possible. Disable all features not required for the primary use case. Require explicit user opt-in to enable additional features. Apply principle of least functionality — only enable what is needed. Unnecessary wireless radios create wireless attack vectors that network segmentation cannot fully address.', 'domain': 'IoT Security - OWASP IoT Top 10'}, {'question': 'Which regulation passed in the UK in 2024 specifically addresses OWASP IoT Top 10 I1 Weak Passwords by legally requiring unique per-device credentials?', 'options': [{'text': 'The UK General Data Protection Regulation (UK GDPR) which requires protection of personal data processed by IoT devices', 'explanation': 'UK GDPR covers personal data protection broadly. The specific regulation legally requiring unique per-device IoT credentials and banning default passwords is a different UK law focused specifically on IoT product security.', 'correct': False}, {'text': 'The UK Product Security and Telecommunications Infrastructure (PSTI) Act 2024 which bans default passwords and requires unique per-device credentials', 'explanation': 'Correct. The UK PSTI Act 2024 is one of the first laws specifically addressing IoT security. It bans universal default passwords, requires manufacturers to publish vulnerability disclosure policies, and mandates minimum security requirements for consumer connectable products sold in the UK.', 'correct': True}, {'text': 'The UK Network and Information Systems (NIS) Regulations which require cybersecurity for critical infrastructure operators', 'explanation': 'NIS Regulations cover critical infrastructure operators not IoT device manufacturers. The PSTI Act 2024 specifically targets IoT product security requirements for manufacturers.', 'correct': False}, {'text': 'The UK Computer Misuse Act which criminalises unauthorised access to IoT devices', 'explanation': 'The Computer Misuse Act criminalises hacking activities. The PSTI Act 2024 specifically requires IoT manufacturers to implement security requirements including unique per-device credentials.', 'correct': False}], 'overall_explanation': 'The UK PSTI Act 2024 IoT security requirements: no universal default passwords (unique per-device credentials required), published vulnerability disclosure policy, minimum security update support period must be stated. This is landmark legislation addressing OWASP I1 at the regulatory level. Similar requirements are developing in the EU Cyber Resilience Act and US IoT Cybersecurity Improvement Act.', 'domain': 'IoT Security - OWASP IoT Top 10'}]